import{_ as o,o as r,c as e,ag as s}from"./chunks/framework.BLeoozAw.js";const u=JSON.parse('{"title":"SRC 攻防实操手册","description":"从 0 到 1 的漏洞挖掘攻防全向图谱，汇聚实战中的血与泪。","frontmatter":{"title":"SRC 攻防实操手册","description":"从 0 到 1 的漏洞挖掘攻防全向图谱，汇聚实战中的血与泪。"},"headers":[],"relativePath":"experience/README.md","filePath":"experience/README.md"}'),i={name:"experience/README.md"};function a(l,t,n,c,p,g){return r(),e("div",null,[...t[0]||(t[0]=[s('<h1 id="🛡️-src-攻防实战经验库-security-playbooks" tabindex="-1">🛡️ SRC 攻防实战经验库 (Security Playbooks) <a class="header-anchor" href="#🛡️-src-攻防实战经验库-security-playbooks" aria-label="Permalink to &quot;🛡️ SRC 攻防实战经验库 (Security Playbooks)&quot;">​</a></h1><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p><strong>探索路线</strong>: 本部分按照<strong>漏洞类型</strong>与<strong>攻击向量</strong>进行模块化。每篇 Playbook 均遵循“漏洞原理 -&gt; 攻坚重难点 -&gt; 自动化思路”的职业级闭环。</p></div><h2 id="💡-核心攻坚战术" tabindex="-1">💡 核心攻坚战术 <a class="header-anchor" href="#💡-核心攻坚战术" aria-label="Permalink to &quot;💡 核心攻坚战术&quot;">​</a></h2><p>这里的每一篇文章都是从上千个 403、500 报错中提炼出的财富：</p><ul><li><strong>权限绕过</strong>: 403 不代表结束，往往是精彩的开始。</li><li><strong>逻辑缺陷</strong>: 业务逻辑是人类思维的投影，脆弱而多变。</li><li><strong>注入进阶</strong>: 现代 WAF 下的 Payload 进化论。</li></ul><hr><h2 id="🏆-白帽进阶指南-如何成为-p1-p0-捕手" tabindex="-1">🏆 白帽进阶指南：如何成为 P1/P0 捕手 <a class="header-anchor" href="#🏆-白帽进阶指南-如何成为-p1-p0-捕手" aria-label="Permalink to &quot;🏆 白帽进阶指南：如何成为 P1/P0 捕手&quot;">​</a></h2><ol><li><strong>资产深挖</strong>: 国内优先攻击<strong>核心资产</strong>（边缘资产收益极低）。优先测试中高危，通过低危漏洞建立信心。</li><li><strong>逆向思维</strong>: 始终以<strong>开发者的视角</strong>思考：如果是我想实现这个功能，我会如何写代码？我会漏掉什么样的校验逻辑？</li><li><strong>思路闭环</strong>: <ul><li>🔍 发现点位 (Discovery)</li><li>🧪 复现验证 (Reproduction)</li><li>📜 沉淀思路 (Summarization)</li><li>🤖 自动化 (Automation)</li></ul></li><li><strong>执着与身体</strong>: 兴趣是第一动力，但在卷的同时，请务必保证休息。</li></ol><hr><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><strong>贡献者须知</strong>: 如果你也有好的实战故事，只需在 <code>experience/</code> 下创建一个目录并提交 Markdown，我们的<strong>自动化引擎</strong>会自动为你完成同步。</p></div><hr>',11)])])}const h=o(i,[["render",a]]);export{u as __pageData,h as default};
